-- EOS MODULE SCHEMA

CREATE TABLE eos_scorecard_metrics (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  goal_operator TEXT NOT NULL,
  goal_value TEXT NOT NULL,
  metric_type TEXT NOT NULL, -- 'currency', 'number', 'percentage', 'decimal', 'boolean'
  display_order INTEGER NOT NULL DEFAULT 0,
  owner_name TEXT,
  owner_email TEXT,
  active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE eos_scorecard_entries (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  metric_id UUID REFERENCES eos_scorecard_metrics(id) ON DELETE CASCADE,
  week_start DATE NOT NULL,
  value TEXT,
  created_by TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(metric_id, week_start)
);

CREATE TABLE eos_barrels (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  description TEXT,
  owner_name TEXT,
  owner_email TEXT,
  status TEXT DEFAULT 'not_started',
  due_date DATE,
  quarter TEXT,
  barrel_type TEXT DEFAULT 'company',
  created_by TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE eos_barrel_milestones (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  barrel_id UUID REFERENCES eos_barrels(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  completed BOOLEAN DEFAULT false,
  due_date DATE,
  display_order INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE eos_todos (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  owner_name TEXT,
  owner_email TEXT,
  due_date DATE,
  completed BOOLEAN DEFAULT false,
  completed_at TIMESTAMPTZ,
  created_from_meeting_id UUID,
  created_by TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE eos_opportunities (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  description TEXT,
  priority TEXT,
  owner_name TEXT,
  owner_email TEXT,
  term TEXT DEFAULT 'short',
  status TEXT DEFAULT 'open',
  created_by TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE eos_headlines (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  headline_type TEXT DEFAULT 'good_news',
  owner_name TEXT,
  created_by TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE eos_meetings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  meeting_type TEXT DEFAULT 'level_10',
  started_at TIMESTAMPTZ,
  ended_at TIMESTAMPTZ,
  rating INTEGER,
  notes TEXT,
  created_by TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE eos_meeting_notes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  meeting_id UUID REFERENCES eos_meetings(id) ON DELETE CASCADE,
  section TEXT NOT NULL,
  content TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ENABLE RLS
ALTER TABLE eos_scorecard_metrics ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_scorecard_entries ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_barrels ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_barrel_milestones ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_todos ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_opportunities ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_headlines ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_meetings ENABLE ROW LEVEL SECURITY;
ALTER TABLE eos_meeting_notes ENABLE ROW LEVEL SECURITY;

-- RLS POLICIES: only authenticated users with allowed emails
