CREATE POLICY "eos_admins_only" ON eos_barrels FOR ALL USING (auth.jwt() ->> 'email' IN ('pheintzman@highbankco.com', 'ahines@highbankco.com'));
CREATE POLICY "eos_admins_only" ON eos_barrel_milestones FOR ALL USING (auth.jwt() ->> 'email' IN ('pheintzman@highbankco.com', 'ahines@highbankco.com'));
CREATE POLICY "eos_admins_only" ON eos_todos FOR ALL USING (auth.jwt() ->> 'email' IN ('pheintzman@highbankco.com', 'ahines@highbankco.com'));
CREATE POLICY "eos_admins_only" ON eos_opportunities FOR ALL USING (auth.jwt() ->> 'email' IN ('pheintzman@highbankco.com', 'ahines@highbankco.com'));
CREATE POLICY "eos_admins_only" ON eos_headlines FOR ALL USING (auth.jwt() ->> 'email' IN ('pheintzman@highbankco.com', 'ahines@highbankco.com'));
CREATE POLICY "eos_admins_only" ON eos_meetings FOR ALL USING (auth.jwt() ->> 'email' IN ('pheintzman@highbankco.com', 'ahines@highbankco.com'));
CREATE POLICY "eos_admins_only" ON eos_meeting_notes FOR ALL USING (auth.jwt() ->> 'email' IN ('pheintzman@highbankco.com', 'ahines@highbankco.com'));

